parameters.jsCode:
// Parse `callback_data` produced by alert workflows (ADR-0038, Wave 3
// §3.2). Format is `ack:<r|i|m>:<alertId>` where the action prefix is
// kept short to fit Telegram's 64-byte budget for callback_data:
//   - `r` → "read"          (terminal acknowledgement)
//   - `i` → "investigating" (soft hand-off)
//   - `m` → "muted"         (suppress re-broadcast in dedup window)
// Anything that doesn't match the prefix is bounced as `noop` so an
// unrelated bot button click (future) doesn't accidentally write to
// `tg_alert_acks`.
const raw = $input.first()?.json ?? {};
const callbackQuery = raw.callback_query ?? raw;
const data = String(callbackQuery?.data ?? '');
const from = callbackQuery?.from ?? {};
const message = callbackQuery?.message ?? {};
const chat = message?.chat ?? {};
const ACTION_MAP = { r: 'read', i: 'investigating', m: 'muted' };
const parts = data.split(':');
let kind = 'noop';
let ackAction = null;
let alertId = null;
if (parts[0] === 'ack' && parts.length >= 3 && ACTION_MAP[parts[1]]) {
  kind = 'ack';
  ackAction = ACTION_MAP[parts[1]];
  alertId = parts.slice(2).join(':');
}
return [{ json: {
  kind,
  alertId,
  ackAction,
  callbackQueryId: callbackQuery?.id ?? null,
  ackByTgUserId: typeof from?.id === 'number' ? from.id : null,
  ackByUsername: from?.username || from?.first_name || 'unknown',
  chatId: chat?.id ?? null,
  messageId: message?.message_id ?? null,
  originalText: message?.text ?? '',
  originalReplyMarkup: message?.reply_markup ?? null,
} }];

// Build the post-ack edited message: original text + ack footer.
// We strip the inline-keyboard (set to empty) so the buttons disappear
// after the click — preventing a second user from acking the same row
// (Phase 5 multi-operator will revisit this, see ADR-0038 §Negative).
// Telegram editMessageText accepts `reply_markup: { inline_keyboard: [] }`
// to drop the buttons.
// `fullResponse: true` is set on the upstream HTTP node, so `$json` is
// `{ statusCode, headers, body }` with the actual API payload nested
// in `body`. Fall back to `$json` itself if the shape is flat (e.g. a
// caller manually disabled fullResponse during smoke-test).
const parsed = $('Parse callback_data').item.json;
const ackResp = $input.first()?.json ?? {};
const statusCode = typeof ackResp?.statusCode === 'number' ? ackResp.statusCode : null;
const ackBody = (ackResp?.body && typeof ackResp.body === 'object') ? ackResp.body : ackResp;
const alreadyAcked = !!ackBody?.alreadyAcked;
const hhmm = new Date().toISOString().slice(11, 16);
const footer = alreadyAcked
  ? `\n\n— already acked (last clicker: @${parsed.ackByUsername} at ${hhmm} UTC)`
  : `\n\n✅ acked by @${parsed.ackByUsername} at ${hhmm} UTC (${parsed.ackAction})`;
const newText = `${parsed.originalText || '(no text)'}${footer}`;
return [{ json: {
  chatId: parsed.chatId,
  messageId: parsed.messageId,
  newText,
  callbackQueryId: parsed.callbackQueryId,
  alreadyAcked,
  statusCode,
  ackResponse: ackBody,
} }];

parameters.jsonBody:
={
  "callback_query_id": "{{ $('Build edited message').item.json.callbackQueryId }}",
  "text": "{{ $('Build edited message').item.json.alreadyAcked ? 'Already acked' : 'Ack recorded' }}",
  "cache_time": 5
}
